class Solution {
public:
    void backtrack(int start, int combinationCount, int targetSum, vector<int>& current, vector<vector<int>>& result) {
        // If the current combination has the required size
        if (current.size() == combinationCount) {
            if (targetSum == 0) {
                result.push_back(current); // Valid combination found
            }
            return;
        }

        for (int i = start; i <= 9; i++) {
            if (i > targetSum) break; // No need to proceed if i exceeds remaining sum
            current.push_back(i);
            backtrack(i + 1, combinationCount, targetSum - i, current, result);
            current.pop_back(); // backtrack
        }
    }

    vector<vector<int>> findCombinations(int combinationCount, int targetSum) {
        vector<vector<int>> result;
        vector<int> current;
        backtrack(1, combinationCount, targetSum, current, result);
        return result;
    }
};

