class Solution {

    private void backtrack(int start, int combinationCount, int targetSum, List<Integer> current, List<List<Integer>> result) {
        if (current.size() == combinationCount) {
            if (targetSum == 0) {
                result.add(new ArrayList<>(current)); // Valid combination found
            }
            return;
        }

        for (int i = start; i <= 9; i++) {
            if (i > targetSum) break; // Optimization: no need to continue
            current.add(i);
            backtrack(i + 1, combinationCount, targetSum - i, current, result);
            current.remove(current.size() - 1); // Backtrack
        }
    }

    public List<List<Integer>> findCombinations(int combinationCount, int targetSum) {
        List<List<Integer>> result = new ArrayList<>();
        backtrack(1, combinationCount, targetSum, new ArrayList<>(), result);
        return result;
    }
}

